private struct HingeSwipeScreen: View {
    @State private var index = 0
    private let profiles = HingeDemoData.profiles
    var body: some View {
        ZStack {
            HingeTokens.hingeDarkCanvas.ignoresSafeArea()
            VStack(spacing: 16) {
                HStack {
                    Image(systemName: "slider.horizontal.3").font(.title2)
                    Spacer()
                    Text("Hinge").font(.system(size: 22, weight: .bold)).foregroundStyle(HingeTokens.hingeCream)
                    Spacer()
                    Image(systemName: "bolt.fill").font(.title2).foregroundStyle(HingeTokens.hingeCream)
                }.padding(.horizontal)
                ZStack {
                    ForEach(Array(profiles.enumerated()), id: \.element.id) { i, profile in
                        if i >= index {
                            HingeSwipeCard(profile: profile, accent: HingeTokens.hingeCream)
                                .scaleEffect(i == index ? 1 : 0.96).offset(y: CGFloat(i - index) * 8)
                        }
                    }
                }.frame(maxHeight: 480)
                HStack(spacing: 24) {
                    HingeActionButton(icon: "xmark", color: .red, size: 56) { if index < profiles.count { index += 1 } }
                    HingeActionButton(icon: "star.fill", color: .blue, size: 48) {}
                    HingeActionButton(icon: "heart.fill", color: HingeTokens.hingeCream, size: 56) { if index < profiles.count { index += 1 } }
                }.padding(.bottom, 8)
            }
        }
    }
}

private struct HingeSwipeCard: View {
    let profile: HingeDatingProfile; let accent: Color
    var body: some View {
        ZStack(alignment: .bottomLeading) {
            RoundedRectangle(cornerRadius: 16).fill(profile.color.gradient).frame(maxWidth: .infinity).frame(height: 440)
            LinearGradient(colors: [.clear, .black.opacity(0.7)], startPoint: .center, endPoint: .bottom)
            VStack(alignment: .leading, spacing: 4) {
                HStack(alignment: .firstTextBaseline) {
                    Text(profile.name).font(.system(size: 28, weight: .bold)).foregroundStyle(.white)
                    Text("\(profile.age)").font(.system(size: 24)).foregroundStyle(.white)
                }
                Text(profile.bio).font(.system(size: 15)).foregroundStyle(.white.opacity(0.9))
            }.padding(20)
        }.padding(.horizontal, 12).shadow(color: .black.opacity(0.15), radius: 12, y: 6)
    }
}

